bash_commands.command:
cat > /workspace/review.json << 'EOF'
[
  {
    "file": "clients/src/main/java/org/apache/kafka/common/security/scram/internals/ScramSaslServer.java",
    "line": 121,
    "severity": "critical",
    "description": "Token expiry validation is missing. The code stores tokenExpiryTimestamp at line 121 but never validates whether the token is expired. An attacker can use expired delegation tokens to bypass authentication.",
    "fix_patch": "--- a/clients/src/main/java/org/apache/kafka/common/security/scram/internals/ScramSaslServer.java
+++ b/clients/src/main/java/org/apache/kafka/common/security/scram/internals/ScramSaslServer.java
@@ -119,6 +119,8 @@
                             if (tokenCallback.tokenOwner() == null)
                                 throw new SaslException("Token Authentication failed: Invalid tokenId : " + username);
                             this.authorizationId = tokenCallback.tokenOwner();
+                            if (tokenCallback.tokenExpiryTimestamp() != null && System.currentTimeMillis() > tokenCallback.tokenExpiryTimestamp())
+                                throw new SaslException("Token has expired");
                             this.tokenExpiryTimestamp = tokenCallback.tokenExpiryTimestamp();
                         } else {
"
  },
  {
    "file": "core/src/main/scala/kafka/security/authorizer/AclAuthorizer.scala",
    "line": 554,
    "severity": "critical",
    "description": "ACL authorization bypass: The range query for prefixed ACLs is inverted due to reverse-order sorting. The .to() bound is exclusive and stops before including single-character prefixes like 't'. This causes shorter prefixed ACLs to never be evaluated, allowing unauthorized access when only a short prefix ACL is configured.",
    "fix_patch": "--- a/core/src/main/scala/kafka/security/authorizer/AclAuthorizer.scala
+++ b/core/src/main/scala/kafka/security/authorizer/AclAuthorizer.scala
@@ -550,10 +550,13 @@
       .getOrElse(mutable.Buffer.empty)

     val prefixed = new ArrayBuffer[AclEntry]
-    aclCacheSnapshot
-      .from(new ResourcePattern(resourceType, resourceName, PatternType.PREFIXED))
-      .to(new ResourcePattern(resourceType, resourceName.take(1), PatternType.PREFIXED))
+    aclCacheSnapshot.foreach { case (resource, acls) =>
+      if (resource.patternType == PatternType.PREFIXED &&
+          resource.resourceType == resourceType &&
+          resourceName.startsWith(resource.name)) {
+        prefixed ++= acls.acls
+      }
+    }
-      .forKeyValue { (resource, acls) =>
-        if (resourceName.startsWith(resource.name)) prefixed ++= acls.acls
-      }

     new AclSeqs(prefixed, wildcard, literal)
"
  }
]
EOF
cat /workspace/review.json

